void hmac_sha256(const uint8_t* key, size_t key_len,
                 const uint8_t* data, size_t data_len,
                 uint8_t out[32]) {
    uint8_t k_pad[64];
    uint8_t tk[32];

    if (key_len > 64) {
        SHA256 ctx;
        ctx.init();
        ctx.update(key, key_len);
        ctx.final(tk);
        key = tk;
        key_len = 32;
    }

    memset(k_pad, 0, 64);
    memcpy(k_pad, key, key_len);

    uint8_t i_pad[64], o_pad[64];
    for (int i = 0; i < 64; i++) {
        i_pad[i] = k_pad[i] ^ 0x36;
        o_pad[i] = k_pad[i] ^ 0x5c;
    }

    // inner hash
    SHA256 ctx;
    ctx.init();
    ctx.update(i_pad, 64);
    ctx.update(data, data_len);
    uint8_t inner[32];
    ctx.final(inner);

    // outer hash
    ctx.init();
    ctx.update(o_pad, 64);
    ctx.update(inner, 32);
    ctx.final(out);
}

bool constant_time_compare(const uint8_t* a, const uint8_t* b, size_t len) {
    uint8_t result = 0;
    for (size_t i = 0; i < len; i++)
        result |= a[i] ^ b[i];
    return result == 0;
}

