struct Vec3 {
    float x, y, z;

    float distance_to(const Vec3& other) const {
        float dx = x - other.x;
        float dy = y - other.y;
        float dz = z - other.z;
        return std::sqrt(dx*dx + dy*dy + dz*dz);
    }

    float length() const {
        return std::sqrt(x*x + y*y + z*z);
    }

    Vec3 normalized() const {
        float len = length();
        if (len < 0.0001f) return {0, 0, 0};
        return {x/len, y/len, z/len};
    }
};

